class Solution {
    public boolean checkInclusion(String s1, String s2) {
        int[] freq1 = new int[26];
        int[] freq2 = new int[26];

        for (char c : s1.toCharArray()) {
            freq1[c - 'a']++;
        }

        for (char c : s2.toCharArray()) {
            freq2[c - 'a']--;
            if (freq2 < 0) {
                return false;
            }
        }

        for (int i = 0; i < s1.length(); i++) {
            if (freq1[s1.charAt(i) - 'a'] == 0) {
                return false;
            }
            freq1[s1.charAt(i) - 'a']--;
        }

        return true;
    }
}
